#!/usr/bin/env python3
# answer_dataset.py — TELE-11 (c): correct-by-construction Q->A pairs for answer-labeled fidelity.
# Labels are COMPUTED in Python (ground truth), not generated by a model. Short, exact-match-verifiable
# answers (the tractable first proof of ANSWERING vs ECHOING on a 0.5B from a pure latent prefix).
#   -> answer_train.jsonl / answer_test.jsonl  (disjoint), each line {"q":..., "a":...}
import json, random, sys
WORDS=["strawberry","banana","mississippi","programming","raspberry","alphabet","telephone","kangaroo",
       "butterfly","watermelon","helicopter","crocodile","umbrella","notebook","elephant","dinosaur",
       "chocolate","pineapple","computer","keyboard","mountain","calendar","hospital","library"]
def tasks(rng, n):
    # ARITHMETIC + PRIME only — tasks the 0.5B provably does from text (text baseline arith 0.806), so the
    # gate isolates CHANNEL fidelity, not the model's char-counting tokenization weakness.
    out=[]
    while len(out)<n:
        k=rng.random()
        if k<0.34:
            a,b=rng.randint(2,50),rng.randint(2,50); out.append((f"what is {a} plus {b}", str(a+b)))
        elif k<0.62:
            a,b=rng.randint(2,20),rng.randint(2,12); out.append((f"what is {a} times {b}", str(a*b)))
        elif k<0.82:
            a,b=rng.randint(20,99),rng.randint(2,19); out.append((f"what is {a} minus {b}", str(a-b)))
        else:
            n2=rng.randint(2,99); pr=all(n2%i for i in range(2,int(n2**0.5)+1)) and n2>1
            out.append((f"is {n2} a prime number, answer yes or no", "yes" if pr else "no"))
    return out
def main():
    rng=random.Random(2026)
    allp=list({(q,a) for q,a in tasks(rng,600)})           # dedup
    rng.shuffle(allp); cut=int(len(allp)*0.85)
    tr,te=allp[:cut],allp[cut:]
    for name,rows in (("answer_train.jsonl",tr),("answer_test.jsonl",te)):
        open(name,"w",encoding="utf-8").write("\n".join(json.dumps({"q":q,"a":a}) for q,a in rows)+"\n")
    print(f"wrote answer_train.jsonl ({len(tr)}) + answer_test.jsonl ({len(te)})  e.g. {tr[0]}")
if __name__=="__main__": main()
